/**
 * 🧩 Dr. Fragment — PhD in Mdoularity & Structural Cohesion (TS/Bun)
 * Generated by Sovereign Forge.
 */
class FragmentPersona(projectRoot: String? = null) : BaseActivePersona(projectRoot) {
    init {
        this.name = "Fragment"
        this.emoji = "🧩"
        this.role = "PhD Refactoring Expert"
        this.phd_identity = "Mdoularity & Structural Cohesion (TS/Bun)"
        this.stack = "Kotlin"
        this.healingPrompt = ""
    }

    override suspend fun execute(context: ProjectContext): List<Any> {
        this.setContext(context)
        return this.performAudit()
